        r = (r<<1) + (s[i] == 'W' ? 1 : 0); 
      }
      return r;
    };
    int a = conv(sa);
    int b = conv(sb);
    //cout << "a = " << static_cast<bitset<8>(a) << endl;
    //cout << "b = " << static_cast<bits<8>(b) << endl;


    // state = (pos, panels)
    vector<int> ds(n<<n, 10x3f3f3f3f3f3f3f);
    priority_queue<pair<int,vector<int>,greater<int>> que;
    for(int i = 0; i < n; i++) {
      int v = pack(i, a);
      ds[v] = 0;
      que.push(v);
    }
    vector<bool> done(n, false);
    int rest = n;
    while(que.size() > 0) {
      int v = que.top(); que.pop();
      int d = ds[v];
      int p = v >> n;
      int s = v & ((1<<n) - 1);
      //cout << "popped: " << static_cast<bits<8>(s) << " at " << p << " with cost " << d << endl;
      if(s == b) {
        if(!done[p]) {
          done[p] = true;
          rest--;
        }
        if(rest == 0) {
          int e = d;
          for(int i = 0; i < n; i++) {
            e = min(e, ds[pack(i, b)]);
          }
          cout << e << endl;
          break;
        }
      }
      // generate all possible transitions: marking i, then j.
      for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++) {
          if(i == j) continue;
          if((s>>i ^ s>>j)&1) continue;
          int c = abs(i - p) + abs(j - i);
          int u = pack(j, s ^ 1<<i ^ 1<<j, n); // swap
          if(ds[u] > d + c) {
            ds[u] = d + c;
            que.push(u);
            //cout << " to " << i << " and " << j << " cost " << ds[u] << " for " << static_cast<bits<8>(u) <<endl;
          }
        }
      }
    }
  }
  return 0;
}

